cloud_function.response_success:
{
  "success": true,
  "recipeTitle": String,
  "recipeUrl": String,
  "ingredients": [
    {
      "name": String,
      "quantity": Number,
      "unit": String,
      "category": String
    }
  ]
}

component.property:
itemBuilder: (context, index) => Card(
                child: ListTile(
                  title: Text(tempItems[index].name),
                  subtitle: Text("${tempItems[index].quantity} ${tempItems[index].unit}"),
                  trailing: IconButton(
                    icon: Icons.close,
                    onPressed: () => _removeTempItem(index)
                  )
                )
              )

child: ListView.builder(
              itemCount: archives.length + 1,
              itemBuilder: (context, index) {
                if (index == archives.length) {
                  return hasMore ? LoadMoreButton(onPressed: _loadMoreArchives) : SizedBox.shrink();
                }
                return ArchiveCard(
                  archive: archives[index],
                  onTap: () => Navigator.pushNamed('/archive-detail/${archives[index].id}'),
                  onDelete: () => _deleteArchive(archives[index])
                );
              }
            )

confirmDismiss: (direction) async {
                return await showDialog(
                  context: context,
                  builder: (context) => AlertDialog(
                    title: Text("Hapus Arsip?"),
                    content: Text("Arsip ini akan dihapus permanen."),
                    actions: [
                      TextButton("Batal"),
                      TextButton("Hapus", style: destructive)
                    ]
                  )
                );
              }

itemBuilder: (context, index) {
              final category = groupedItems.keys.elementAt(index);
              final items = groupedItems[category];
              return Column(
                CategoryHeader(category),
                ...items.map((item) => ListTile(
                  leading: Checkbox(value: item.isChecked, onChanged: null),
                  title: Text(
                    item.name,
                    style: item.isChecked ? TextStyle(decoration: TextDecoration.lineThrough) : null
                  ),
                  subtitle: Text("${item.quantity} ${item.unit}"),
                  enabled: false
                ))
              );
            }

itemBuilder: (context, index) {
              if (isLoading) return RecipeCardSkeleton();
              return RecipeCard(
                recipe: recipes[index],
                onTap: () => Navigator.pushNamed('/recipe-detail/${recipes[index].id}')
              );
            }

actions: [
            IconButton(icon: Icons.share, color: Colors.white, onPressed: () => _shareRecipe())
          ]

decoration: LinearGradient(
                  begin: Alignment.topCenter,
                  end: Alignment.bottomCenter,
                  colors: [Colors.transparent, Colors.black54]
                )
